import React from 'react';
import './App.css';
import 'antd/dist/antd.css'; // or 'antd/dist/antd.less'
import { Table, Input, Button, Popconfirm, Form } from 'antd';
import Axios from 'axios';

const axios = Axios.create();

const EditableContext = React.createContext();

const EditableRow = ({ form, index, ...props }) => (
  <EditableContext.Provider value={form}>
    <tr {...props} />
  </EditableContext.Provider>
);

const EditableFormRow = Form.create()(EditableRow);

class EditableCell extends React.Component {
  state = {
    editing: false,
  };

  toggleEdit = () => {
    const editing = !this.state.editing;
    this.setState({ editing }, () => {
      if (editing) {
        this.input.focus();
      }
    });
  };

  save = e => {
    const { record, handleSave } = this.props;
    this.form.validateFields((error, values) => {
      if (error && error[e.currentTarget.id]) {
        return;
      }
      this.toggleEdit();
      handleSave({ ...record, ...values });
    });
  };

  renderCell = form => {
    this.form = form;
    const { children, dataIndex, record, title } = this.props;
    const { editing } = this.state;
    return editing ? (
      <Form.Item style={{ margin: 0 }}>
        {form.getFieldDecorator(dataIndex, {
          rules: [
            {
              required: true,
              message: `${title} is required.`,
            },
          ],
          initialValue: record[dataIndex],
        })(<Input ref={node => (this.input = node)} onPressEnter={this.save} onBlur={this.save} />)}
      </Form.Item>
    ) : (
      <div
        className="editable-cell-value-wrap"
        style={{ paddingRight: 24 }}
        onClick={this.toggleEdit}
      >
        {children}
      </div>
    );
  };

  render() {
    const {
      editable,
      dataIndex,
      title,
      record,
      index,
      handleSave,
      children,
      ...restProps
    } = this.props;
    return (
      <td {...restProps}>
        {editable ? (
          <EditableContext.Consumer>{this.renderCell}</EditableContext.Consumer>
        ) : (
          children
        )}
      </td>
    );
  }
}

export default class EditableTable extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      dataSource : [],
      count : 0,
      size : 'small'
    };
    this.columns = [];
    axios.get("https://uchkks.cn:8002/file/get?file=12-28-sltz.csv")
    .then((response) => {
      let data = response.data[0];
      if (data["code"] !== "2000") {
        console.log("Error" + data["code"] + ":" + data["msg"] + ", errormsg : " + data["errmsg"]);
        return;
      }
      data = response.data[0]["data"];
      if (data[0] === null || data[0] === undefined) {
        return;
      }
      let columnslen = data[0].length;
      let columns = data[0];
      for (let i = 0; i < columnslen; ++i) {
        this.columns.push({
          title : columns[i],
          dataIndex : columns[i],
          editable : true
        })
      }
      this.columns.push({
        title: '操作',
        dataIndex: '操作',
        render: (text, record) =>
          this.state.dataSource.length >= 1 ? (
            <Popconfirm title="确认删除?" onConfirm={() => this.handleDelete(record.key)}>
              <a>Delete</a>
            </Popconfirm>
          ) : null,
      });
      let datasource = [];
      for (let i = 1; i < data.length; ++i) {
        let map = {};
        map['key'] = String(i - 1);
        for (let j = 0; j < columnslen; ++j) {
          map[columns[j]] = data[i][j];
        }
        datasource.push(map);
      }
      this.setState({
        dataSource : datasource,
        count : datasource.length
      });
    })
    .catch((error) => {
      console.log(error);
    })
  }

  handleDelete = key => {
    const dataSource = [...this.state.dataSource];
    this.setState({ dataSource: dataSource.filter(item => item.key !== key) });
  };

  handleAdd = () => {
    const { count, dataSource } = this.state;
    let newData = {};
    newData['key'] = count;
    for (let i = 0; i < this.columns.length - 1; i++) {
      const element = this.columns[i];
      newData[element.dataIndex] = "NULL";
    }
    this.setState({
      dataSource: [...dataSource, newData],
      count: count + 1,
    });
  };

  handleSave = row => {
    const newData = [...this.state.dataSource];
    const index = newData.findIndex(item => row.key === item.key);
    const item = newData[index];
    newData.splice(index, 1, {
      ...item,
      ...row,
    });
    this.setState({ dataSource: newData });
  };

  render() {
    const { dataSource } = this.state;
    const components = {
      body: {
        row: EditableFormRow,
        cell: EditableCell,
      },
    };
    const columns = this.columns.map(col => {
      if (!col.editable) {
        return col;
      }
      return {
        ...col,
        onCell: record => ({
          record,
          editable: col.editable,
          dataIndex: col.dataIndex,
          title: col.title,
          handleSave: this.handleSave,
        }),
      };
    });
    return (
      <div>
        <Button onClick={this.handleAdd} type="primary" style={{ marginBottom: 16 }}>
          添加新行
        </Button>
        <Table
          components={components}
          rowClassName={() => 'editable-row'}
          bordered
          dataSource={dataSource}
          columns={columns}
        />
        <Button onClick={this.exportCSV} type="primary" style={{ marginBottom: 16 }}>
          提交
        </Button>
      </div>
    );
  }
}
